using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests;

internal static class TestHelpers
{
    /// <summary>
    /// Creates a fresh in-memory SchoolContext for each test.
    /// Uses a unique database name to ensure test isolation.
    /// </summary>
    public static SchoolContext CreateInMemoryContext()
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
            .Options;
        return new SchoolContext(options);
    }

    /// <summary>
    /// Seeds the context with basic reference data useful for controller tests.
    /// </summary>
    public static void SeedTestData(SchoolContext context)
    {
        var instructor = new Instructor
        {
            ID = 1,
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = DateTime.Parse("1995-03-11")
        };
        context.Instructors.Add(instructor);

        var department = new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 350000,
            StartDate = DateTime.Parse("2007-09-01"),
            InstructorID = 1
        };
        context.Departments.Add(department);

        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 1
        };
        context.Courses.Add(course);

        var student = new Student
        {
            ID = 1,
            FirstMidName = "Carson",
            LastName = "Alexander",
            EnrollmentDate = DateTime.Parse("2010-09-01")
        };
        context.Students.Add(student);

        var enrollment = new Enrollment
        {
            EnrollmentID = 1,
            CourseID = 1050,
            StudentID = 1,
            Grade = Grade.A
        };
        context.Enrollments.Add(enrollment);

        context.SaveChanges();
    }
}

using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models;

[TestClass]
public sealed class PersonTests
{
    [TestMethod]
    public void FullName_ReturnsLastNameCommaFirstName()
    {
        var student = new Student { LastName = "Smith", FirstMidName = "John" };

        Assert.AreEqual("Smith, John", student.FullName);
    }

    [TestMethod]
    public void FullName_WithEmptyFirstName_ReturnsLastNameComma()
    {
        var student = new Student { LastName = "Smith", FirstMidName = "" };

        Assert.AreEqual("Smith, ", student.FullName);
    }
}

using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models;

[TestClass]
public sealed class ErrorViewModelTests
{
    [TestMethod]
    public void ShowRequestId_WhenRequestIdIsSet_ReturnsTrue()
    {
        var model = new ErrorViewModel { RequestId = "abc123" };

        Assert.IsTrue(model.ShowRequestId);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void ShowRequestId_WhenRequestIdIsNullOrEmpty_ReturnsFalse(string? requestId)
