using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    [TestMethod]
    public void SendNotification_ThenReceive_ReturnsNotification()
    {
        using var sut = new NotificationService();

        sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

        var notification = sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
        Assert.IsTrue(notification.Message.Contains("John Doe"));
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        using var sut = new NotificationService();

        sut.SendNotification("Course", "42", EntityOperation.UPDATE);

        var notification = sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("ID: 42"));
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        using var sut = new NotificationService();

        sut.SendNotification("Student", "1", EntityOperation.CREATE);

        var notification = sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void ReceiveNotification_WhenEmpty_ReturnsNull()
    {
        // Drain any pre-existing notifications from the static queue
        using var sut = new NotificationService();
        while (sut.ReceiveNotification() != null) { }

        var result = sut.ReceiveNotification();

        Assert.IsNull(result);
    }

    [TestMethod]
    public void SendNotification_MultipleMessages_DequeuedInOrder()
    {
        using var sut = new NotificationService();

        sut.SendNotification("A", "1", EntityOperation.CREATE);
        sut.SendNotification("B", "2", EntityOperation.UPDATE);
        sut.SendNotification("C", "3", EntityOperation.DELETE);

        Assert.AreEqual("A", sut.ReceiveNotification()!.EntityType);
        Assert.AreEqual("B", sut.ReceiveNotification()!.EntityType);
        Assert.AreEqual("C", sut.ReceiveNotification()!.EntityType);
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, "has been created")]
    [DataRow(EntityOperation.UPDATE, "has been updated")]
    [DataRow(EntityOperation.DELETE, "has been deleted")]
    public void SendNotification_GeneratesCorrectMessage(EntityOperation operation, string expectedPhrase)
    {
        using var sut = new NotificationService();

        sut.SendNotification("Entity", "1", "TestEntity", operation);

        var notification = sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains(expectedPhrase),
            $"Message '{notification.Message}' should contain '{expectedPhrase}'");
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        using var sut = new NotificationService();

        // MarkAsRead is a no-op for in-memory; just verify it doesn't throw
        sut.MarkAsRead(999);
    }

    [TestMethod]
    public void Dispose_CanBeCalledMultipleTimes()
    {
        var sut = new NotificationService();
        sut.Dispose();
        sut.Dispose(); // should not throw
    }
}

