using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class HomeControllerTests
{
    private SchoolContext _context = null!;
    private HomeController _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _sut = new HomeController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        var result = _sut.Index();

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void About_WithStudents_ReturnsEnrollmentGroups()
    {
        _context.Students.Add(new Student
        {
            FirstMidName = "Alice",
            LastName = "Smith",
            EnrollmentDate = DateTime.Parse("2020-09-01")
        });
        _context.Students.Add(new Student
        {
            FirstMidName = "Bob",
            LastName = "Jones",
            EnrollmentDate = DateTime.Parse("2020-09-01")
        });
        _context.Students.Add(new Student
        {
            FirstMidName = "Carol",
            LastName = "White",
            EnrollmentDate = DateTime.Parse("2021-09-01")
        });
        _context.SaveChanges();

        var result = _sut.About() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);

        var group2020 = model.Single(g => g.EnrollmentDate == DateTime.Parse("2020-09-01"));
        Assert.AreEqual(2, group2020.StudentCount);

        var group2021 = model.Single(g => g.EnrollmentDate == DateTime.Parse("2021-09-01"));
        Assert.AreEqual(1, group2021.StudentCount);
    }

    [TestMethod]
    public void About_NoStudents_ReturnsEmptyList()
    {
        var result = _sut.About() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    [TestMethod]
    public void Contact_SetsViewBagMessage()
    {
        var result = _sut.Contact() as ViewResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Your contact page.", _sut.ViewBag.Message);
    }

    [TestMethod]
    public void Error_ReturnsViewResult()
    {
        var result = _sut.Error();

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Unauthorized_SetsViewBagMessage()
    {
        var result = _sut.Unauthorized() as ViewResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("You don't have permission to access this resource.", _sut.ViewBag.Message);
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context = null!;
    private StudentsController _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _sut = new StudentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut.Dispose();
        _context.Dispose();
    }

    private void SeedStudents()
    {
        _context.Students.AddRange(
            new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2010-09-01") },
            new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2012-09-01") },
            new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2013-09-01") },
            new Student { FirstMidName = "Gytis", LastName = "Barzdukas", EnrollmentDate = DateTime.Parse("2012-09-01") }
        );
        _context.SaveChanges();
    }

    // ----- Index -----

    [TestMethod]
    public void Index_DefaultSort_OrdersByLastNameAscending()
    {
        SeedStudents();

        var result = _sut.Index(null, null, null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_NameDescSort_OrdersByLastNameDescending()
    {
        SeedStudents();

        var result = _sut.Index("name_desc", null, null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual("Barzdukas", model[0].LastName);
    }

    [TestMethod]
    public void Index_DateSort_OrdersByEnrollmentDateAscending()
    {
        SeedStudents();

        var result = _sut.Index("Date", null, null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(DateTime.Parse("2010-09-01"), model[0].EnrollmentDate);
    }

    [TestMethod]
    public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
    {
        SeedStudents();

        var result = _sut.Index("date_desc", null, null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(DateTime.Parse("2013-09-01"), model[0].EnrollmentDate);
    }

    [TestMethod]
    public void Index_WithSearchString_FiltersStudents()
    {
        SeedStudents();

        var result = _sut.Index(null, null, "Alex", null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_WithSearchString_SetsPageTo1()
    {
        SeedStudents();

        var result = _sut.Index(null, null, "Alex", 3) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.PageIndex);
    }

    [TestMethod]
    public void Index_NullSearchString_UsesCurrentFilter()
    {
        SeedStudents();

        var result = _sut.Index(null, "Alonso", null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alonso", model[0].LastName);
    }

    [TestMethod]
    public void Index_SetsViewBagSortParms()
    {
        SeedStudents();

        _sut.Index(null, null, null, null);

        Assert.AreEqual("name_desc", _sut.ViewBag.NameSortParm);
        Assert.AreEqual("Date", _sut.ViewBag.DateSortParm);
    }

    [TestMethod]
    public void Index_WhenSortOrderIsDate_SetsDateDescParm()
    {
        SeedStudents();

        _sut.Index("Date", null, null, null);

        Assert.AreEqual("date_desc", _sut.ViewBag.DateSortParm);
    }

    // ----- Details -----

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _sut.Details(null) as StatusCodeResult;

        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsStudentWithEnrollments()
    {
        TestHelpers.SeedTestData(_context);

        var result = _sut.Details(1) as ViewResult;

        Assert.IsNotNull(result);
        var student = result.Model as Student;
        Assert.IsNotNull(student);
        Assert.AreEqual("Alexander", student.LastName);
        Assert.AreEqual(1, student.Enrollments.Count);
    }

    // ----- Create GET -----

    [TestMethod]
    public void Create_Get_ReturnsViewWithStudentAndTodaysDate()
    {
        var result = _sut.Create() as ViewResult;

        Assert.IsNotNull(result);
        var student = result.Model as Student;
        Assert.IsNotNull(student);
        Assert.AreEqual(DateTime.Today, student.EnrollmentDate);
    }

    // ----- Create POST -----

    [TestMethod]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.Parse("2023-09-01")
        };

        var result = _sut.Create(student) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(1, _context.Students.Count());
    }

    [TestMethod]
    public void Create_Post_MinValueDate_AddsModelError()
    {
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _sut.Create(student) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsFalse(_sut.ModelState.IsValid);
        Assert.IsTrue(_sut.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        _sut.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "",
            EnrollmentDate = DateTime.Parse("2023-09-01")
        };

        var result = _sut.Create(student) as ViewResult;

        Assert.IsNotNull(result);
        Assert.AreEqual(student, result.Model);
    }

    // ----- Edit GET -----

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _sut.Edit((int?)null) as StatusCodeResult;

        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_NotFound_ReturnsNotFound()
    {
        var result = _sut.Edit(999) as NotFoundResult;

        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsStudentView()
    {
        TestHelpers.SeedTestData(_context);

        var result = _sut.Edit(1) as ViewResult;

        Assert.IsNotNull(result);
        var student = result.Model as Student;
        Assert.IsNotNull(student);
        Assert.AreEqual("Alexander", student.LastName);
    }

    // ----- Edit POST -----

    [TestMethod]
    public void Edit_Post_ValidStudent_RedirectsToIndex()
    {
        TestHelpers.SeedTestData(_context);
        // Detach tracked entity to avoid conflict
        var existingStudent = _context.Students.Find(1)!;
        _context.Entry(existingStudent).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var student = new Student
        {
            ID = 1,
            FirstMidName = "Carson",
            LastName = "Updated",
            EnrollmentDate = DateTime.Parse("2010-09-01")
        };

