using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Data;

[TestClass]
public sealed class SchoolContextTests
{
    [TestMethod]
    public void SchoolContext_CanCreateAndQueryEntities()
    {
        using var context = TestHelpers.CreateInMemoryContext();

        context.Students.Add(new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.Parse("2023-09-01")
        });
        context.SaveChanges();

        var student = context.Students.Single();
        Assert.AreEqual("Test", student.FirstMidName);
        Assert.AreEqual("Student", student.LastName);
    }

    [TestMethod]
    public void SchoolContext_CourseAssignment_HasCompositeKey()
    {
        using var context = TestHelpers.CreateInMemoryContext();

        var instructor = new Instructor
        {
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = DateTime.Parse("1995-03-11")
        };
        context.Instructors.Add(instructor);

        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Test",
            Budget = 100000,
            StartDate = DateTime.Now
        };
        context.Departments.Add(dept);

        var course = new Course
        {
            CourseID = 1000,
            Title = "Test Course",
            Credits = 3,
            DepartmentID = 1
        };
        context.Courses.Add(course);
        context.SaveChanges();

        var assignment = new CourseAssignment
        {
            InstructorID = instructor.ID,
            CourseID = 1000
        };
        context.CourseAssignments.Add(assignment);
        context.SaveChanges();

        var result = context.CourseAssignments.Single();
        Assert.AreEqual(instructor.ID, result.InstructorID);
        Assert.AreEqual(1000, result.CourseID);
    }

    [TestMethod]
    public void SchoolContext_InstructorOfficeAssignment_OneToOne()
    {
        using var context = TestHelpers.CreateInMemoryContext();

        var instructor = new Instructor
        {
            FirstMidName = "Roger",
            LastName = "Harui",
            HireDate = DateTime.Parse("1998-07-01")
        };
        context.Instructors.Add(instructor);
        context.SaveChanges();

        context.OfficeAssignments.Add(new OfficeAssignment
        {
            InstructorID = instructor.ID,
            Location = "Gowan 27"
        });
        context.SaveChanges();

        var loaded = context.Instructors
            .Include(i => i.OfficeAssignment)
            .Single(i => i.ID == instructor.ID);

        Assert.IsNotNull(loaded.OfficeAssignment);
        Assert.AreEqual("Gowan 27", loaded.OfficeAssignment.Location);
    }

    [TestMethod]
    public void SchoolContext_Enrollment_LinksStudentAndCourse()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        TestHelpers.SeedTestData(context);

        var enrollment = context.Enrollments
            .Include(e => e.Course)
            .Include(e => e.Student)
            .Single();

        Assert.AreEqual("Chemistry", enrollment.Course.Title);
        Assert.AreEqual("Alexander", enrollment.Student.LastName);
        Assert.AreEqual(Grade.A, enrollment.Grade);
    }

    [TestMethod]
    public void SchoolContext_Notifications_CanPersist()
    {
        using var context = TestHelpers.CreateInMemoryContext();

        context.Notifications.Add(new Notification
        {
            EntityType = "Student",
            EntityId = "1",
            Operation = "CREATE",
            Message = "Test notification",
            CreatedAt = DateTime.Now,
            CreatedBy = "System",
            IsRead = false
        });
        context.SaveChanges();

        Assert.AreEqual(1, context.Notifications.Count());
        Assert.AreEqual("Student", context.Notifications.Single().EntityType);
    }
}
