namespace ContosoUniversity.Tests.Data;

[TestClass]
public sealed class DbInitializerTests
{
    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsAllData()
    {
        using var context = TestHelpers.CreateInMemoryContext();

        DbInitializer.Initialize(context);

        Assert.AreEqual(8, context.Students.Count());
        Assert.AreEqual(5, context.Instructors.Count());
        Assert.AreEqual(4, context.Departments.Count());
        Assert.AreEqual(7, context.Courses.Count());
        Assert.AreEqual(3, context.OfficeAssignments.Count());
        Assert.AreEqual(8, context.CourseAssignments.Count());
        Assert.IsTrue(context.Enrollments.Count() > 0);
    }

    [TestMethod]
    public void Initialize_AlreadySeeded_DoesNotDuplicate()
    {
        using var context = TestHelpers.CreateInMemoryContext();

        DbInitializer.Initialize(context);
        var studentCount = context.Students.Count();

        // Call again — should be a no-op
        DbInitializer.Initialize(context);

        Assert.AreEqual(studentCount, context.Students.Count());
    }

    [TestMethod]
    public void Initialize_SetsCorrectStudentData()
    {
        using var context = TestHelpers.CreateInMemoryContext();

        DbInitializer.Initialize(context);

        var carson = context.Students.Single(s => s.LastName == "Alexander");
        Assert.AreEqual("Carson", carson.FirstMidName);
        Assert.AreEqual(DateTime.Parse("2010-09-01"), carson.EnrollmentDate);
    }

    [TestMethod]
    public void Initialize_SetsDepartmentAdministrators()
    {
        using var context = TestHelpers.CreateInMemoryContext();

        DbInitializer.Initialize(context);

        var english = context.Departments.Single(d => d.Name == "English");
        Assert.IsNotNull(english.InstructorID);
    }

    [TestMethod]
    public void Initialize_CreatesCourseAssignments()
    {
        using var context = TestHelpers.CreateInMemoryContext();

        DbInitializer.Initialize(context);

        // Chemistry should have 2 instructors
        var chemAssignments = context.CourseAssignments
            .Where(ca => ca.CourseID == context.Courses.Single(c => c.Title == "Chemistry").CourseID)
            .ToList();
        Assert.AreEqual(2, chemAssignments.Count);
    }
}
