using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class HomeControllerTests
{
    private SchoolContext _context = null!;
    private HomeController _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _sut = new HomeController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        var result = _sut.Index();

        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void About_WithStudents_ReturnsEnrollmentGroups()
    {
        _context.Students.Add(new Student
        {
            FirstMidName = "Alice",
            LastName = "Smith",
            EnrollmentDate = DateTime.Parse("2020-09-01")
        });
        _context.Students.Add(new Student
        {
            FirstMidName = "Bob",
            LastName = "Jones",
            EnrollmentDate = DateTime.Parse("2020-09-01")
        });
        _context.Students.Add(new Student
        {
            FirstMidName = "Carol",
            LastName = "White",
            EnrollmentDate = DateTime.Parse("2021-09-01")
