using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class DepartmentsControllerTests
{
    private SchoolContext _context = null!;
    private DepartmentsController _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _sut = new DepartmentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut.Dispose();
        _context.Dispose();
    }

    // ----- Index -----

    [TestMethod]
    public void Index_ReturnsAllDepartments()
    {
        TestHelpers.SeedTestData(_context);

        var result = _sut.Index() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as List<Department>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Engineering", model[0].Name);
    }

    [TestMethod]
    public void Index_NoDepartments_ReturnsEmptyList()
    {
        var result = _sut.Index() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as List<Department>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    // ----- Details -----

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _sut.Details(null) as StatusCodeResult;

        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Details_NotFound_ReturnsNotFound()
    {
        var result = _sut.Details(999) as NotFoundResult;

        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsDepartment()
    {
        TestHelpers.SeedTestData(_context);

        var result = _sut.Details(1) as ViewResult;

        Assert.IsNotNull(result);
        var dept = result.Model as Department;
        Assert.IsNotNull(dept);
        Assert.AreEqual("Engineering", dept.Name);
    }

    // ----- Create GET -----

    [TestMethod]
    public void Create_Get_ReturnsView()
    {
        TestHelpers.SeedTestData(_context);

        var result = _sut.Create() as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsNotNull(_sut.ViewBag.InstructorID);
    }

    // ----- Create POST -----

    [TestMethod]
    public void Create_Post_ValidDepartment_RedirectsToIndex()
    {
        TestHelpers.SeedTestData(_context);

        var department = new Department
        {
            Name = "Mathematics",
            Budget = 100000,
            StartDate = DateTime.Parse("2007-09-01"),
            InstructorID = 1
        };

        var result = _sut.Create(department) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(2, _context.Departments.Count());
    }

    [TestMethod]
    public void Create_Post_InvalidModel_ReturnsViewWithDepartment()
    {
        TestHelpers.SeedTestData(_context);
        _sut.ModelState.AddModelError("Name", "Required");

        var department = new Department
        {
            Budget = 100000,
            StartDate = DateTime.Parse("2007-09-01")
        };

        var result = _sut.Create(department) as ViewResult;

        Assert.IsNotNull(result);
        Assert.AreEqual(department, result.Model);
        Assert.IsNotNull(_sut.ViewBag.InstructorID);
    }

    // ----- Edit GET -----

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _sut.Edit((int?)null) as StatusCodeResult;

        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_NotFound_ReturnsNotFound()
    {
        var result = _sut.Edit(999) as NotFoundResult;

        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsDepartment()
    {
        TestHelpers.SeedTestData(_context);

        var result = _sut.Edit(1) as ViewResult;

        Assert.IsNotNull(result);
        var dept = result.Model as Department;
        Assert.IsNotNull(dept);
        Assert.AreEqual("Engineering", dept.Name);
        Assert.IsNotNull(_sut.ViewBag.InstructorID);
    }

    // ----- Edit POST -----

    [TestMethod]
    public void Edit_Post_ValidDepartment_RedirectsToIndex()
    {
        TestHelpers.SeedTestData(_context);
        var existing = _context.Departments.Find(1)!;
        _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var department = new Department
        {
            DepartmentID = 1,
            Name = "Updated Engineering",
            Budget = 400000,
            StartDate = DateTime.Parse("2007-09-01"),
            InstructorID = 1
        };

        var result = _sut.Edit(department) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Edit_Post_InvalidModel_ReturnsViewWithDepartment()
    {
        TestHelpers.SeedTestData(_context);
        _sut.ModelState.AddModelError("Name", "Required");

        var department = new Department
        {
            DepartmentID = 1,
            Name = "",
            Budget = 100000,
            StartDate = DateTime.Parse("2007-09-01")
        };

        var result = _sut.Edit(department) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsNotNull(_sut.ViewBag.InstructorID);
    }

    // ----- Delete GET -----

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _sut.Delete(null) as StatusCodeResult;

        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_NotFound_ReturnsNotFound()
    {
        var result = _sut.Delete(999) as NotFoundResult;

        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsDepartment()
    {
        TestHelpers.SeedTestData(_context);

        var result = _sut.Delete(1) as ViewResult;

        Assert.IsNotNull(result);
        var dept = result.Model as Department;
        Assert.IsNotNull(dept);
        Assert.AreEqual("Engineering", dept.Name);
    }

    // ----- DeleteConfirmed -----

    [TestMethod]
    public void DeleteConfirmed_RemovesDepartmentAndRedirects()
    {
        TestHelpers.SeedTestData(_context);

        var result = _sut.DeleteConfirmed(1) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(0, _context.Departments.Count());
    }
}

