using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class CoursesControllerTests
{
    private SchoolContext _context = null!;
    private CoursesController _sut = null!;
    private Mock<IWebHostEnvironment> _envMock = null!;
    private Mock<ILogger<CoursesController>> _loggerMock = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _envMock = new Mock<IWebHostEnvironment>();
        _envMock.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
        _envMock.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
        _loggerMock = new Mock<ILogger<CoursesController>>();
        _sut = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut.Dispose();
        _context.Dispose();
    }

    // ----- Index -----

    [TestMethod]
    public void Index_ReturnsAllCourses()
    {
        TestHelpers.SeedTestData(_context);

        var result = _sut.Index() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Chemistry", model[0].Title);
    }

    [TestMethod]
    public void Index_NoCourses_ReturnsEmptyList()
    {
        var result = _sut.Index() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    // ----- Details -----

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _sut.Details(null) as StatusCodeResult;

        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsCourse()
    {
        TestHelpers.SeedTestData(_context);

        var result = _sut.Details(1050) as ViewResult;

        Assert.IsNotNull(result);
        var course = result.Model as Course;
        Assert.IsNotNull(course);
        Assert.AreEqual("Chemistry", course.Title);
        Assert.IsNotNull(course.Department);
    }

    // ----- Create GET -----

    [TestMethod]
    public void Create_Get_ReturnsViewWithEmptyCourse()
    {
        TestHelpers.SeedTestData(_context);

        var result = _sut.Create() as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsInstanceOfType<Course>(result.Model);
        Assert.IsNotNull(_sut.ViewBag.DepartmentID);
    }

    // ----- Create POST -----

    [TestMethod]
    public void Create_Post_ValidCourse_RedirectsToIndex()
    {
        TestHelpers.SeedTestData(_context);

        var course = new Course
        {
            CourseID = 2000,
            Title = "Physics",
            Credits = 3,
            DepartmentID = 1
        };

        var result = _sut.Create(course, null!) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(2, _context.Courses.Count());
    }

    [TestMethod]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        TestHelpers.SeedTestData(_context);
        _sut.ModelState.AddModelError("Title", "Required");

        var course = new Course
        {
            CourseID = 2000,
            Title = "",
            Credits = 3,
            DepartmentID = 1
        };

        var result = _sut.Create(course, null!) as ViewResult;

        Assert.IsNotNull(result);
        Assert.AreEqual(course, result.Model);
        Assert.IsNotNull(_sut.ViewBag.DepartmentID);
    }

    // ----- Edit GET -----

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _sut.Edit((int?)null) as StatusCodeResult;

        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_NotFound_ReturnsNotFound()
    {
        var result = _sut.Edit(999) as NotFoundResult;

        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsCourse()
    {
        TestHelpers.SeedTestData(_context);

        var result = _sut.Edit(1050) as ViewResult;

        Assert.IsNotNull(result);
        var course = result.Model as Course;
        Assert.IsNotNull(course);
        Assert.AreEqual("Chemistry", course.Title);
        Assert.IsNotNull(_sut.ViewBag.DepartmentID);
    }

    // ----- Edit POST -----

    [TestMethod]
    public void Edit_Post_ValidCourse_RedirectsToIndex()
    {
        TestHelpers.SeedTestData(_context);
        var existing = _context.Courses.Find(1050)!;
        _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var course = new Course
        {
            CourseID = 1050,
            Title = "Updated Chemistry",
            Credits = 4,
            DepartmentID = 1
        };

        var result = _sut.Edit(course, null!) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Edit_Post_InvalidModel_ReturnsView()
    {
        TestHelpers.SeedTestData(_context);
        _sut.ModelState.AddModelError("Title", "Required");

        var course = new Course
        {
            CourseID = 1050,
            Title = "",
            Credits = 3,
            DepartmentID = 1
        };

        var result = _sut.Edit(course, null!) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsNotNull(_sut.ViewBag.DepartmentID);
    }

    // ----- Delete GET -----

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _sut.Delete(null) as StatusCodeResult;

        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsCourse()
    {
        TestHelpers.SeedTestData(_context);

        var result = _sut.Delete(1050) as ViewResult;

        Assert.IsNotNull(result);
        var course = result.Model as Course;
        Assert.IsNotNull(course);
        Assert.AreEqual("Chemistry", course.Title);
    }

    // ----- DeleteConfirmed -----

    [TestMethod]
    public void DeleteConfirmed_RemovesCourseAndRedirects()
    {
        TestHelpers.SeedTestData(_context);

        var result = _sut.DeleteConfirmed(1050) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(0, _context.Courses.Count());
    }

    [TestMethod]
    public void DeleteConfirmed_WithImagePath_RemovesCourse()
    {
        TestHelpers.SeedTestData(_context);
        var course = _context.Courses.Find(1050)!;
        course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test.jpg";
        _context.SaveChanges();

        var result = _sut.DeleteConfirmed(1050) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(0, _context.Courses.Count());
    }
}

