using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class InstructorsControllerTests
{
    private SchoolContext _context = null!;
    private InstructorsController _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _sut = new InstructorsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut.Dispose();
        _context.Dispose();
    }

    private void SeedInstructorWithCourses()
    {
        var instructor = new Instructor
        {
            ID = 1,
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = DateTime.Parse("1995-03-11"),
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Instructors.Add(instructor);

        var department = new Department
        {
            DepartmentID = 1,
            Name = "English",
            Budget = 350000,
            StartDate = DateTime.Parse("2007-09-01"),
            InstructorID = 1
        };
        _context.Departments.Add(department);

        var course = new Course
        {
            CourseID = 2021,
            Title = "Composition",
            Credits = 3,
            DepartmentID = 1,
            Enrollments = new List<Enrollment>()
        };
        _context.Courses.Add(course);

        var assignment = new CourseAssignment
        {
            InstructorID = 1,
            CourseID = 2021
        };
        _context.CourseAssignments.Add(assignment);
        _context.SaveChanges();
    }

    // ----- Index -----

    [TestMethod]
    public void Index_NoParams_ReturnsAllInstructors()
    {
        SeedInstructorWithCourses();

        var result = _sut.Index(null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Instructors.Count());
    }

    [TestMethod]
    public void Index_WithInstructorId_PopulatesCourses()
    {
        SeedInstructorWithCourses();

        var result = _sut.Index(1, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Courses);
        Assert.AreEqual(1, model.Courses.Count());
        Assert.AreEqual("Composition", model.Courses.First().Title);
    }

    [TestMethod]
    public void Index_WithCourseId_PopulatesEnrollments()
    {
        SeedInstructorWithCourses();
        // Add an enrollment for the course
        _context.Students.Add(new Student
        {
            ID = 10,
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.Parse("2020-09-01")
        });
        _context.Enrollments.Add(new Enrollment
        {
            EnrollmentID = 100,
            CourseID = 2021,
            StudentID = 10,
            Grade = Grade.A
        });
        _context.SaveChanges();

        var result = _sut.Index(1, 2021) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Enrollments);
        Assert.AreEqual(1, model.Enrollments.Count());
    }

    // ----- Details -----

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _sut.Details(null) as StatusCodeResult;

        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Details_NotFound_ReturnsNotFound()
    {
        var result = _sut.Details(999) as NotFoundResult;

        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsInstructor()
    {
        SeedInstructorWithCourses();

        var result = _sut.Details(1) as ViewResult;

        Assert.IsNotNull(result);
        var instructor = result.Model as Instructor;
        Assert.IsNotNull(instructor);
        Assert.AreEqual("Abercrombie", instructor.LastName);
    }

    // ----- Create GET -----

    [TestMethod]
    public void Create_Get_ReturnsInstructorWithEmptyCourseAssignments()
    {
        SeedInstructorWithCourses();

        var result = _sut.Create() as ViewResult;

        Assert.IsNotNull(result);
        var instructor = result.Model as Instructor;
        Assert.IsNotNull(instructor);
        Assert.IsNotNull(instructor.CourseAssignments);
        Assert.AreEqual(0, instructor.CourseAssignments.Count);
        Assert.IsNotNull(_sut.ViewBag.Courses);
    }

    // ----- Create POST -----

    [TestMethod]
    public void Create_Post_ValidInstructor_RedirectsToIndex()
    {
        var instructor = new Instructor
        {
            FirstMidName = "New",
            LastName = "Instructor",
            HireDate = DateTime.Parse("2020-01-15"),
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = _sut.Create(instructor, null!) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
    {
        SeedInstructorWithCourses();

        var instructor = new Instructor
        {
            FirstMidName = "New",
            LastName = "Instructor",
            HireDate = DateTime.Parse("2020-01-15"),
            CourseAssignments = new List<CourseAssignment>()
        };
        var selectedCourses = new[] { "2021" };

        var result = _sut.Create(instructor, selectedCourses) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        SeedInstructorWithCourses();
        _sut.ModelState.AddModelError("LastName", "Required");

        var instructor = new Instructor
        {
            FirstMidName = "New",
            LastName = "",
            HireDate = DateTime.Parse("2020-01-15"),
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = _sut.Create(instructor, null!) as ViewResult;

        Assert.IsNotNull(result);
    }

    // ----- Delete GET -----

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _sut.Delete(null) as StatusCodeResult;

        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_NotFound_ReturnsNotFound()
    {
        var result = _sut.Delete(999) as NotFoundResult;

        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsInstructor()
    {
        SeedInstructorWithCourses();

        var result = _sut.Delete(1) as ViewResult;

        Assert.IsNotNull(result);
        var instructor = result.Model as Instructor;
        Assert.IsNotNull(instructor);
        Assert.AreEqual("Abercrombie", instructor.LastName);
    }

    // ----- DeleteConfirmed -----

    [TestMethod]
    public void DeleteConfirmed_RemovesInstructorAndRedirects()
    {
        SeedInstructorWithCourses();
        // Add OfficeAssignment so the Include works
        _context.OfficeAssignments.Add(new OfficeAssignment
        {
            InstructorID = 1,
            Location = "Smith 17"
        });
        _context.SaveChanges();

        var result = _sut.DeleteConfirmed(1) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(0, _context.Instructors.Count());
    }

    [TestMethod]
    public void DeleteConfirmed_NullsDepartmentAdministrator()
    {
        SeedInstructorWithCourses();

        var result = _sut.DeleteConfirmed(1) as RedirectToActionResult;

        Assert.IsNotNull(result);
        var dept = _context.Departments.Find(1);
        Assert.IsNotNull(dept);
        Assert.IsNull(dept.InstructorID);
    }
}

