using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context = null!;
    private NotificationsController _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _sut = new NotificationsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void GetNotifications_WhenNotificationsExist_ReturnsThemWithSuccess()
    {
        // Seed a notification by using the service directly
        var service = new NotificationService();
        service.SendNotification("Test", "1", "TestItem", EntityOperation.CREATE, "admin");

        var result = _sut.GetNotifications();

        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Value);
        service.Dispose();
    }

    [TestMethod]
    public void GetNotifications_WhenEmpty_ReturnsSuccessWithZeroCount()
    {
        // Drain any pre-existing static queue items
        var service = new NotificationService();
        while (service.ReceiveNotification() != null) { }
        service.Dispose();

        var result = _sut.GetNotifications();

        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Value);
    }

    [TestMethod]
    public void MarkAsRead_ReturnsSuccessJson()
    {
        var result = _sut.MarkAsRead(1);

        Assert.IsNotNull(result);
        Assert.IsNotNull(result.Value);
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        var result = _sut.Index();

        Assert.IsInstanceOfType<ViewResult>(result);
    }
}

